mapper.select:
SELECT TO_CHAR(dual_dt.DISPLAY_DATE, 'YYYY. MM. DD') AS CCTN_DT , NVL(tbivcl.VSTO_CNT, 0) AS VSTO_CNT FROM ( SELECT TO_DATE(#{searchFromDate}, 'YYYY. MM. DD') + LEVEL - 1 AS DISPLAY_DATE FROM DUAL CONNECT BY
LEVEL <= TO_DATE(#{searchToDate}, 'YYYY. MM. DD') - TO_DATE(#{searchFromDate}, 'YYYY. MM. DD') + 1
) dual_dt LEFT JOIN ( SELECT TO_DATE(CCTN_DT, 'YYYY. MM. DD') AS CCTN_DT , VSTO_CNT FROM TB_BOX_IVT_VSTO_CCTN_L ) tbivcl ON dual_dt.DISPLAY_DATE = tbivcl.CCTN_DT ORDER BY dual_dt.DISPLAY_DATE DESC
